import './Post.css'
import React, { Component } from 'react'
import { Link } from 'react-router-dom';

export default class Post extends Component {
    constructor(props) {
        super(props)
    
        this.state = {
            actBtn: false
        }
    }
    
    render() {
        const { img, id, title, tags } = this.props.list
        return (
            <Link to={`/posts/${id}`} className="card-post" onMouseMove={()=>{this.setState({actBtn:true})}} onMouseOut={()=>{this.setState({actBtn:false})}}>
                <div className={this.state.actBtn ? "tags-block" : "d-none"}>{tags}</div>
                <img className="img-post" width="100%" src={img} alt={`title: ${title}`} />
            </Link >
        )
    }
}
